static int32_t* createTupleIndex(size_t rows) {
  void* index = taosMemoryCalloc(rows, sizeof(int32_t));
  if (index == NULL) {
    return NULL;
  }

  for (int32_t i = 0; i < rows; ++i) {
    ((int32_t*)index)[i] = i;
  }

  return (int32_t*)index;
}

static void destroyTupleIndex(int32_t* index) { taosMemoryFreeClear(index); }

static int32_t compareDoubleVal(const void* pLeft, const void* pRight, const void* param) {
  double* data = (double*)param;
  double leftVal = data[*(int32_t*)pLeft];
  double rightVal = data[*(int32_t*)pRight];
  return compareDoubleVal(&leftVal, &rightVal);
}

